def _load_sibling_module(module_name):
    """Load a sibling generated module when this file is imported directly."""
    path = Path(__file__).with_name(f'{module_name}.py')
    spec = importlib.util.spec_from_file_location(f'_pbc_release_{module_name}', path)
    module = importlib.util.module_from_spec(spec)
    if spec.loader is None:
        raise ImportError(module_name)
    spec.loader.exec_module(module)
    return module


def _build_schema_contract():
    try:
        from .schema_contract import build_schema_contract
    except ImportError:
        return _load_sibling_module('schema_contract').build_schema_contract()
    return build_schema_contract()


def _build_service_contract():
    try:
        from .service_contract import build_service_contract
    except ImportError:
        return _load_sibling_module('service_contract').build_service_contract()
    return build_service_contract()


def build_release_evidence():
    """Return generated release audit evidence for this PBC."""
    runtime_evidence = runtime_release_evidence()
    workflow = ar_credit_workflow_release_evidence()
    service_surface = service_operation_manifest()
    ui_surface = ar_credit_ui_contract()
    agent_surface = {
        "skills": agent_skill_manifest(),
        "chatbot": chatbot_interface_contract(),
    }
    extra_checks = (
        {
            "id": "service_workflow_surface",
            "ok": "execute_receipt_application" in service_surface.get("workflow_operations", ()),
        },
        {
            "id": "ui_workflow_surface",
            "ok": "build_collections_follow_up" in ui_surface.get("workflow_actions", ()),
        },
        {
            "id": "agent_preview_surface",
            "ok": any(
                skill["name"].endswith("cash_application_preview")
                for skill in agent_surface["skills"].get("skills", ())
            ),
        },
    )
    checks = tuple(runtime_evidence.get("checks", ())) + extra_checks
    evidence = {
        **dict(RELEASE_EVIDENCE),
        **runtime_evidence,
        "format": "appgen.ar-credit-release-evidence.v1",
        "pbc": "ar_credit",
        "schema": runtime_evidence.get("schema", _build_schema_contract()),
        "service": runtime_evidence.get("service", _build_service_contract()),
        "workflow_slice": workflow,
        "service_surface": service_surface,
        "ui": ui_surface,
        "agent": agent_surface,
        "checks": checks,
    }
    evidence["ok"] = all(check.get("ok") is True for check in checks)
    evidence["blocking_gaps"] = tuple(check for check in checks if check.get("ok") is not True)
    return evidence


def release_readiness_manifest():
    """Return side-effect-free release evidence coverage and gate metadata."""
    evidence = build_release_evidence()
    sections = tuple(
        name
        for name in ('schema', 'service', 'api', 'permissions', 'ui', 'agent', 'workflow_slice', 'service_surface')
        if isinstance(evidence.get(name), dict)
    )
    checks = tuple(evidence.get('checks', ()))
    return {
        'ok': evidence.get('ok') is True and bool(checks),
        'pbc': 'ar_credit',
        'format': evidence.get('format'),
        'sections': sections,
        'checks': checks,
        'blocking_gaps': tuple(evidence.get('blocking_gaps', ())),
        'required_sections': ('schema', 'service'),
        'side_effects': (),
    }


def validate_release_evidence():
    """Validate release evidence, blocking gaps, and owned-boundary proof."""
    evidence = build_release_evidence()
    manifest = release_readiness_manifest()
    missing_sections = tuple(section for section in manifest['required_sections'] if section not in manifest['sections'])
    failed_checks = tuple(check for check in manifest['checks'] if check.get('ok') is not True)
    schema = evidence.get('schema', {}) if isinstance(evidence.get('schema'), dict) else {}
    service = evidence.get('service', {}) if isinstance(evidence.get('service'), dict) else {}
    workflow = evidence.get('workflow_slice', {}) if isinstance(evidence.get('workflow_slice'), dict) else {}
    service_surface = evidence.get('service_surface', {}) if isinstance(evidence.get('service_surface'), dict) else {}
    boundary_gaps = tuple(
        gap
        for gap, failed in (
            ('schema_shared_table_access', schema.get('shared_table_access') is not False),
            ('service_shared_table_access', service.get('shared_table_access') is True),
            ('service_missing_command_methods', not bool(service.get('command_methods'))),
            ('workflow_shared_table_access', workflow.get('shared_table_access') is not False),
            ('workflow_not_appgen_x', workflow.get('event_contract') != 'AppGen-X'),
            ('service_workflow_not_exposed', not bool(service_surface.get('workflow_operations'))),
        )
        if failed
    )
    return {
        'ok': manifest['ok']
        and evidence.get('pbc') == manifest['pbc']
        and not manifest['blocking_gaps']
        and not missing_sections
        and not failed_checks
        and not boundary_gaps,
        'pbc': 'ar_credit',
        'manifest': manifest,
        'missing_sections': missing_sections,
        'failed_checks': failed_checks,
        'boundary_gaps': boundary_gaps,
        'side_effects': (),
    }


def smoke_test():
    """Exercise release evidence readiness validation side-effect-free."""
    validation = validate_release_evidence()
    evidence = build_release_evidence()
    return {
        'ok': validation['ok'] and evidence.get('ok') is True,
        'validation': validation,
        'evidence': evidence,
        'side_effects': (),
    }
